import React, { useState } from "react";

export default function Chatbot({ weatherData }) {
  const [messages, setMessages] = useState([{ role: "bot", text: "Hi! Ask me about today's weather or activities." }]);
  const [input, setInput] = useState("");

  const sendMessage = () => {
    if (!input.trim()) return;

    const userMsg = { role: "user", text: input };
    const botMsg = { role: "bot", text: getWeatherResponse(input, weatherData) };

    setMessages((prev) => [...prev, userMsg, botMsg]);
    setInput("");
  };

  const getWeatherResponse = (question, data) => {
    if (!data || !data.current) return "I don't have the weather data right now.";

    const temp = data.current.temp;
    const condition = data.current.weather[0].main.toLowerCase();
    const wind = data.current.wind_speed;
    const rainChance = data.hourly?.[0]?.pop * 100 || 0;

    question = question.toLowerCase();

    // Simple activity checks
    if (question.includes("badminton")) {
      if (rainChance > 30) return "Not ideal for badminton — looks like it might rain.";
      if (wind > 20) return "Too windy for badminton today.";
      if (temp < 10) return "A bit too cold for badminton.";
      return `Yes! It's ${Math.round(temp)}°C, ${condition}, and winds are calm — perfect for badminton.`;
    }

    if (question.includes("swim") || question.includes("swimming")) {
      if (rainChance > 50) return "Not great — high chance of rain.";
      if (temp < 20) return "Too cold to swim comfortably.";
      return `Sure! It's ${Math.round(temp)}°C and ${condition}. Enjoy your swim!`;
    }

    if (question.includes("hike") || question.includes("hiking")) {
      if (rainChance > 40) return "Might not be the best — rain is likely.";
      if (temp > 35) return "Too hot for a safe hike today.";
      return `Great day for hiking! It's ${Math.round(temp)}°C and ${condition}.`;
    }

    // Fallback
    return `Right now it's ${Math.round(temp)}°C with ${condition}. What activity are you thinking of?`;
  };

  return (
    <div className="p-4 bg-black/40 backdrop-blur-md rounded-xl flex flex-col h-full">
      <div className="flex-1 overflow-y-auto mb-2 space-y-2">
        {messages.map((msg, idx) => (
          <div
            key={idx}
            className={`p-2 rounded-lg max-w-[80%] ${msg.role === "bot" ? "bg-purple-600 text-white self-start" : "bg-gray-200 text-black self-end"}`}
          >
            {msg.text}
          </div>
        ))}
      </div>
      <div className="flex gap-2">
        <input
          className="flex-1 px-3 py-2 rounded-lg bg-white/20 text-white placeholder-white/70"
          placeholder="Ask me about the weather..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && sendMessage()}
        />
        <button onClick={sendMessage} className="px-4 py-2 bg-purple-600 rounded-lg text-white">
          Send
        </button>
      </div>
    </div>
  );
}
